aaam_marketing_consent__blocking_text__text_locking = TextObject(bs_BA="Ograničeno rukovanje u toku vožnje.", cs_CZ="Omezená obsluha během jízdy.", da_DK="Begrænset betjening under kørsel.", de_DE="Eingeschränkte Bedienung während der Fahrt.", el_GR="Περιορισμένος χειρισμός κατά τη διάρκεια της οδήγησης.", en_GB="For your safety, limited operation while driving.", es_ES="Manejo limitado durante la marcha.", fi_FI="Rajoitettu käyttö ajon aikana.", fr_FR="Utilisation restreinte pendant la conduite.", hr_HR="Ograničeno rukovanje tijekom vožnje.", hu_HU="Korlátozott használat menet közben.", it_IT="Utilizzo limitato durante la marcia.", nl_NL="Beperkte bediening tijdens het rijden.", no_NO="Betjening er begrenset under kjøring.", pl_PL="Ograniczona obsługa podczas jazdy.", pt_PT="Acionamento com restrições durante a circulação.", ro_RO="Operare limitată în timpul deplasării.", ru_RU="Во время движения управление ограничено.", sk_SK="Obmedzená obsluha počas jazdy.", sl_SI="Omejeno upravljanje med vožnjo.", sr_RS="Ograničeno rukovanje u toku vožnje.", sv_SE="Begränsad användning under körning.", tr_TR="Sürüş sırasında sınırlı kullanım.", uk_UA="Під час руху керування обмежено.")
aaam_marketing_consent__decline_button__label = TextObject(bs_BA="Odbij", cs_CZ="Odmítnout", da_DK="Afvis", de_DE="Ablehnen", el_GR="Απόρριψη", en_GB="Decline", es_ES="Rechazar", fi_FI="Hylkää", fr_FR="Refuser", hr_HR="Odbiti", hu_HU="Elutasítás", it_IT="Rifiuta", nl_NL="Afwijzen", no_NO="Avvis", pl_PL="Odrzuć", pt_PT="Rejeitar", ro_RO="Respingere", ru_RU="Отклонить", sk_SK="Odmietnuť", sl_SI="Zavrnitev", sr_RS="Odbij", sv_SE="Avvisa", tr_TR="Reddet", uk_UA="Відхилити")
aaam_marketing_consent__explanation__text = TextObject(bs_BA="Budite u toku i primajte aktuelne informacije o temama u MMI.\nVašu odluku možete uvijek promijeniti u postavkama.", cs_CZ="Zůstaňte v obraze a získejte aktuální informace o tématech v MMI.\nSvé rozhodnutí můžete kdykoli změnit v nastavení.", da_DK="Hold dig ajour, og modtag aktuelle informationer om temaerne i MMI.\nDu kan til enhver tid ændre din beslutning i indstillingerne.", de_DE="Bleibe auf dem Laufenden und erhalte aktuelle Informationen zu den Themes im MMI.\nDu kannst deine Entscheidung jederzeit in den Einstellungen ändern.", el_GR="Παραμένετε ενήμεροι και λαμβάνετε τις τελευταίες πληροφορίες σχετικά με τα θέματα του MMI.\nΜπορείτε να αλλάξετε την απόφασή σας ανά πάσα στιγμή στις ρυθμίσεις.", en_GB="Stay up to date and receive the latest information about themes on the MMI. You can change\nyour decision at any time in the settings.", es_ES="Manténgase al día y reciba en el MMI información actualizada sobre las temáticas.\nPuede cambiar su decisión en todo momento en los ajustes.", fi_FI="Pysy ajan tasalla ja vastaanota ajantasaisia tietoja MMI:n teemoista. Voit muuttaa päätöstäsi\nmilloin tahansa asetuksissa.", fr_FR="Restez à jour et obtenez des informations actuelles sur les thèmes dans le MMI.\nVous pouvez à tout moment modifier votre décision dans les réglages.", hr_HR="Budite u toku i primajte sve aktualne informacije o temama u MML-u.\nSvoju odluku možete promijeniti u svakom trenutku u postavkama.", hu_HU="Maradj naprakész, és kapd meg a legfrissebb információkat az MMI témáiról.\nBármikor módosítatod a döntésedet a beállításokban.", it_IT="Rimanga aggiornato e riceva le ultime informazioni sui Temi nell'MMI. È possibile modificare\nquesta decisione nelle impostazioni in qualsiasi momento.", nl_NL="Blijf op de hoogte en ontvang actuele informatie over de thema's in de MMI. Je kunt je\nbeslissing op elk moment wijzigen in de instellingen.", no_NO="Hold deg oppdatert og få nyheter om temaene i MMI.\nDu kan når som helst endre valget ditt i innstillingene.", pl_PL="Bądź na bieżąco i otrzymuj najnowsze informacje o tematach w MMI.\nDecyzję możesz zmienić w każdej chwili w Ustawieniach.", pt_PT="Mantém-te onde estás e recebe informações atuais relativas ao tema no MMI. Em qualquer\naltura podes alterar a tua decisão nos ajustes.", ro_RO="Rămâneţi la curent şi recepţionaţi toate informaţiile actuale cu privire la temă în MMI.\nPuteţi să vă schimbaţi decizia în orice moment, în setări.", ru_RU="Оставайтесь в курсе событий и получайте самую свежую информацию по темам в MMI. Вы\nможете в любой момент изменить свое решение в настройках.", sk_SK="Zostaňte v obraze a získavajte aktuálne informácie o témach v systéme MMI.\nSvoje rozhodnutie môžete kedykoľvek zmeniť v nastaveniach.", sl_SI="Ostanite na tekočem in prejemajte aktualne informacije o temah v sistemu MMI.\nSvojo odločitev lahko kadar koli spremenite v nastavitvah.", sr_RS="Budite u toku i primajte aktuelne informacije o temama u MMI.\nVašu odluku možete uvek izmeniti u podešavanjima.", sv_SE="Håll dig uppdaterad och få aktuell information om teman i MMI.\nDu kan när som helst ändra ditt val i inställningarna.", tr_TR="Güncel kalın ve MMI'daki temalar hakkında güncel bilgiler alın.\nKararını istediğin zaman ayarlar üzerinden değiştirebilirsin.", uk_UA="Будьте в курсі подій та отримуйте найсвіжішу інформацію про теми в MMI. Ви можете\nзмінити своє рішення в будь-який час у налаштуваннях.")
