reasonbackend_switched_off__error_message_text = TextObject(bs_BA="Došlo je do greške. Aktivirajte ovu uslugu na myAudi portalu ili u myAudi aplikaciji. Aplikaciju\nmožete i dalje koristiti u vanmrežnom režimu.", cs_CZ="Došlo k chybě. Aktivujte si tuto službu na portálu myAudi nebo v aplikaci myAudi. Aplikaci\nmůžete stále používat v režimu offline.", da_DK="Fejl opstået. Aktiver denne tjeneste på myAudi-portalen eller i myAudi-appen. Du kan fortsat\nanvende appen i offlineindstillingen.", de_DE="Es ist ein Fehler aufgetreten. Bitte aktiviere diesen Dienst im myAudi Portal oder in der\nmyAudi App. Du kannst die App weiterhin im Offline-Modus nutzen.", el_GR="Παρουσιάστηκε σφάλμα. Ενεργοποιήστε αυτήν την υπηρεσία στη διαδικτυακή πύλη myAudi ή\nστην εφαρμογή myAudi. Μπορείτε να συνεχίσετε να χρησιμοποιείτε την εφαρμογή στη\nλειτουργία offline.", en_GB="An error has occurred. Please activate this service in the myAudi portal or the myAudi app.\nYou can still use the app in offline mode.", es_ES="Se ha producido un error. Active este servicio en el portal myAudi\no en la App myAudi. Puede seguir utilizando la App en modo offline.", fi_FI="Tapahtui virhe. Aktivoi tämä palvelu myAudi-portaalin tai myAudi-sovelluksen kautta. Voit\nedelleen käyttää sovellusta offline-tilassa.", fr_FR="Une erreur s'est produite.\nVeuillez activer ce service sur le portail myAudi ou dans l'application myAudi.\nVous pouvez continuer à utiliser l'application en mode hors ligne.", hr_HR="Nastupila je greška. Aktivirajte ovu uslugu na myAudi portalu ili u myAudi aplikaciji. Aplikaciju\nmožete nastaviti koristiti u offline modusu.", hu_HU="Hiba lépett fel. Aktiváld ezt a szolgáltatást a myAudi portálon vagy a myAudi alkalmazásban.\nOffline módban továbbra is használhatod az alkalmazást.", it_IT="Si è verificato un errore. Attivare questo servizio sul portale myAudi o nell'app myAudi. È\npossibile continuare a utilizzare l'app in modalità offline.", nl_NL="Er is een fout opgetreden. Activeer deze dienst in het myAudi portaal of in de myAudi app. Je\nkunt de app nog steeds gebruiken in de offlinemodus.", no_NO="Det har oppstått en feil. Aktiver tjenesten i myAudi-portalen eller myAudi-appen. Du kan\nfortsatt bruke appen i offline-modus.", pl_PL="Pojawił się błąd. Proszę włączyć tę usługę na portalu myAudi lub w aplikacji myAudi. Możesz\ndalej korzystać z aplikacji w trybie offline.", pt_PT="Ocorreu um erro. Por favor, ative esta serviço no Portal myAudi ou na myAudi app. Podes\ncontinuar a utilizar a aplicação no modo offline.", ro_RO="A survenit o eroare. Activaţi acest serviciu în portalul myAudi sau în aplicaţia myAudi. Puteţi\nutiliza aplicaţia în continuare, în modul offline.", ru_RU="Произошла ошибка. Активируйте этот сервис на портале myAudi или в приложении\nmyAudi. Вы по-прежнему можете использовать приложение в автономном режиме.", sk_SK="Vyskytla sa chyba. Prosím, aktivujte si túto službu na portáli myAudi alebo v aplikácii myAudi.\nAplikáciu môžete používať naďalej v režime offline.", sl_SI="Prišlo je do napake. Storitev aktivirajte na portalu myAudi ali v aplikaciji myAudi. Aplikacijo\nlahko še naprej uporabljate v načinu brez povezave.", sr_RS="Došlo je do greške. Aktivirajte ovu uslugu na portalu myAudi ili u aplikaciji myAudi. Aplikaciju\nmožete da koristite i dalje u vanmrežnom režimu.", sv_SE="Ett fel har uppstått. Aktivera denna tjänst i myAudi-portalen eller i myAudi-appen. Du kan\nfortfarande använda appen i offline-läget.", tr_TR="Bir hata oluştu. Lütfen bu hizmeti myAudi portalında veya myAudi uygulamasında etkinleştir.\nUygulamayı çevrimdışı modda kullanmaya devam edebilirsin.", uk_UA="Сталася помилка. Активуйте цю службу на порталі myAudi або в програмі myAudi. Ви все\nще можете користуватися програмою в автономному режимі.")
reasonbackend_switched_off__titleline_title = TextObject(bs_BA="Tematski svijet: Napomena", cs_CZ="Témata: Poznámka", da_DK="Temaunivers: Bemærk", de_DE="Themenwelt: Hinweis", el_GR="Θεματικός κόσμος: Υπόδειξη", en_GB="Themes: information", es_ES="Configuración temática: Nota", fi_FI="Teema-toiminto: ohje", fr_FR="Univers thématiques: nota", hr_HR="Svijet tema: napomena", hu_HU="Témák: megjegyzés", it_IT="Temi: avvertenza", nl_NL="Themawereld: aanwijzing", no_NO="Temaer: Informasjon", pl_PL="Tematytka: informacja", pt_PT="Temas globais: Indicação", ro_RO="Lume tematică: indicaţie", ru_RU="Темы: примечание", sk_SK="Výber tém: upozornenie", sl_SI="Tematski svet: napotek", sr_RS="Tematski svet: Napomena", sv_SE="Teman: Anvisning", tr_TR="Tema dünyası: Not", uk_UA="Теми: вказівки")
